pricing_agent = Agent(
    role='Pricing Specialist',
    goal='Provide accurate, real-time pricing from verified sources',
    backstory='Ensures PCI-DSS compliance in pricing workflows',
    verbose=True
)

def pricing_vex_check(output):
    validation = guardrail.validate({
        'type': 'pricing',
        'content': output,
        'rules': ['pci_dss', 'accuracy_threshold_0.01'],
        'context': {'source': 'shopify_api'}
    })
    if not validation['passes']:
        raise ValueError(f"Pricing violation: {validation['issues']}")
    return output

price_task = Task(
    description='Fetch current pricing for {product_sku}',
    agent=pricing_agent,
    callback=pricing_vex_check
)

personalization_agent = Agent(
    role='Customer Personalizer',
    goal='Create GDPR/CCPA-compliant personalized experiences',
    backstory='Privacy-first personalization expert',
    verbose=True
)

def privacy_callback(output):
    result = guardrail.validate({
        'type': 'pii_handling',
        'content': output,
        'rules': ['ccpa_consent', 'gdpr_minimization'],
        'metadata': {'user_id': 'anon_123'}
    })
    return result['redacted_output'] if result['passes'] else None

personalize_task = Task(
    description='Personalize experience for customer with preferences {prefs}',
    agent=personalization_agent,
    callback=privacy_callback
)

crew = Crew(agents=[product_agent, pricing_agent, personalization_agent], tasks=[recommend_task, price_task, personalize_task])
